const fs = require('fs');

const md = $input.first().json.body.md_document || "";

if (!md) {
  throw new Error("MD içeriği bulunamadı.");
}

const ts       = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
const base     = `review_${ts}`;
const mdPath   = `/tmp/${base}.md`;
const docxPath = `/tmp/${base}.docx`;

fs.writeFileSync(mdPath, md, "utf-8");

return [{
  json: {
    ...$input.first().json.body,
    md_filepath:   mdPath,
    docx_filepath: docxPath,
    filename_base: base,
  }
}];

const fs = require('fs');

const mdPath       = $('Write .md to a file1').first().json.md_filepath;
const filenameBase = $('Write .md to a file1').first().json.filename_base;

if (!fs.existsSync(mdPath)) {
  throw new Error(`MD dosyası bulunamadı: ${mdPath}`);
}

// MD dosyasını oku ve binary'e çevir
const buffer = fs.readFileSync(mdPath);

const binaryData = await this.helpers.prepareBinaryData(
  buffer,
  `${filenameBase}.md`,
  "text/markdown"
);

// Temizlik
try { fs.unlinkSync(mdPath); } catch {}

return [{
  json: {"filename_base": $input.first().json.filename_base},
  binary: { attachment: binaryData }
}];

const data = $('Webhook1').first().json.body;

const author        = data.author        || "Bilinmiyor";
const commitMessage = data.commit_message || "—";
const repo          = data.repo           || "—";
const branch        = data.branch         || "—";
const timestamp     = data.timestamp      || "—";
const filesChanged  = Array.isArray(data.files_changed) ? data.files_changed : [];
const reasons       = Array.isArray(data.report_reasons) ? data.report_reasons : [];
const hasDocument   = Boolean(data.md_document && data.md_document.trim().length > 0);
const doc_filename  = $input.first().json.filename_base;

// ── Jira base URL (ayrı node'dan) ───────────────────────────────────────────
const jiraBaseUrl = $('Set  Config').first().json.jiraBaseUrl;

// ── Attachment binary'sini bir sonraki node'lara taşı ──────────────────────
// (Attachment sadece md_document doluysa "Convert .md to binary" node'undan gelir.
//  Boşsa error path'ten geliriz ve binary yoktur; bu durumda mail attachment'sız gider.)
const inputBinary = $input.first().binary || {};

// ── Jira issue key ────────────────────────────────────────────────────────────
const jiraMatch   = commitMessage.match(/^([A-Z]+-\d+)/);
const jiraKey     = jiraMatch ? jiraMatch[1] : null;
const jiraKeyHtml = jiraKey
  ? `<a href="${jiraBaseUrl}/browse/${jiraKey}"
       style="color:#1A6FA8;text-decoration:none;font-weight:600;">${jiraKey}</a>`
  : `<span style="color:#95A5A6;font-style:italic;">bulunamadı</span>`;

// ── Formatlı tarih ────────────────────────────────────────────────────────────
const formattedDate = (() => {
  try {
    return new Date(timestamp).toLocaleString("tr-TR", {
      year: "numeric", month: "long", day: "numeric",
      hour: "2-digit", minute: "2-digit", timeZone: "Europe/Istanbul"
    });
  } catch { return timestamp; }
})();

// ── Sebep satırları ───────────────────────────────────────────────────────────
const reasonRows = reasons.map((r, i) => `
  <tr>
    <td style="padding:10px 16px;border-bottom:1px solid #F0F0F0;
      vertical-align:top;width:28px;">
      <span style="display:inline-block;background:#1A6FA8;color:#fff;
        border-radius:50%;width:22px;height:22px;line-height:22px;
        text-align:center;font-size:12px;font-weight:bold;">${i + 1}</span>
    </td>
    <td style="padding:10px 16px;border-bottom:1px solid #F0F0F0;
      font-size:14px;color:#2C3E50;line-height:1.5;">${r}</td>
  </tr>`).join("");

// ── Değişen dosyalar ─────────────────────────────────────────────────────────
const fileList = filesChanged.length > 0
  ? filesChanged.map(f =>
      `<li style="font-family:monospace;font-size:13px;color:#34495E;padding:2px 0;">${f}</li>`
    ).join("")
  : `<li style="font-size:13px;color:#95A5A6;">Dosya bilgisi bulunamadı</li>`;

// ── Attachment notu ───────────────────────────────────────────────────────────
const attachmentNote = hasDocument
  ? `<tr>
      <td style="padding:20px 32px;">
        <table width="100%" cellpadding="0" cellspacing="0"><tr>
          <td style="background:#EBF5FB;border:1px solid #AED6F1;
            border-radius:6px;padding:14px 18px;">
            <p style="margin:0;font-size:13px;color:#1A5276;line-height:1.6;">
              📎 Detaylı AI review analizi için mail ekindeki
              <strong><em>${doc_filename}.md </em></strong>
              dosyasına bakabilirsiniz.<br>
              <span style="color:#2E86C1;">Rapor; kod kalitesi, MISRA uyumluluk
              ve güvenlik analizlerini içermektedir.</span>
            </p>
          </td>
        </tr></table>
      </td>
    </tr>`
  : `<tr>
      <td style="padding:20px 32px;">
        <table width="100%" cellpadding="0" cellspacing="0"><tr>
          <td style="background:#FDFEFE;border:1px solid #D5D8DC;
            border-radius:6px;padding:14px 18px;">
            <p style="margin:0;font-size:13px;color:#717D7E;line-height:1.6;">
              ⚠️ Bu commit için AI review raporu (.md dokümanı) oluşturulamadı,
              bu nedenle mail ekinde herhangi bir dosya bulunmamaktadır.
              Pipeline detaylı analiz üretemeden bypass edilmiştir.
            </p>
          </td>
        </tr></table>
      </td>
    </tr>`;

// ── HTML ──────────────────────────────────────────────────────────────────────
const html = `<!DOCTYPE html>
<html lang="tr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width,initial-scale=1.0">
  <title>Commit Raporu</title>
</head>
<body style="margin:0;padding:0;background:#F4F6F8;
  font-family:Arial,Helvetica,sans-serif;">

<table width="100%" cellpadding="0" cellspacing="0"
  style="background:#F4F6F8;padding:32px 0;">
  <tr><td align="center">
    <table width="620" cellpadding="0" cellspacing="0"
      style="background:#FFFFFF;border-radius:8px;
        box-shadow:0 2px 8px rgba(0,0,0,0.08);overflow:hidden;">

      <!-- Header -->
      <tr>
        <td style="background:#16213E;padding:24px 32px;">
          <p style="margin:0;font-size:11px;color:rgba(255,255,255,0.6);
            letter-spacing:1.5px;text-transform:uppercase;">
            Git Review Pipeline
          </p>
          <h1 style="margin:10px 0 0;font-size:20px;color:#FFFFFF;font-weight:700;">
            Commit Review Raporu
          </h1>
          ${jiraKey ? `
          <p style="margin:8px 0 0;font-size:13px;color:rgba(255,255,255,0.75);">
            Jira:
            <a href="${jiraBaseUrl}/browse/${jiraKey}"
              style="color:#7EC8E3;text-decoration:none;font-weight:600;">
              ${jiraKey}
            </a>
          </p>` : ""}
        </td>
      </tr>

      <!-- Commit Metadata -->
      <tr>
        <td style="padding:24px 32px 0;">
          <h2 style="margin:0 0 14px;font-size:12px;color:#7F8C8D;
            text-transform:uppercase;letter-spacing:1px;font-weight:600;">
            Commit Bilgileri
          </h2>
          <table width="100%" cellpadding="0" cellspacing="0"
            style="border:1px solid #E8E8E8;border-radius:6px;overflow:hidden;">
            <tr style="background:#F8F9FA;">
              <td style="padding:10px 16px;font-size:12px;color:#7F8C8D;
                font-weight:600;width:130px;border-bottom:1px solid #E8E8E8;">
                AUTHOR
              </td>
              <td style="padding:10px 16px;font-size:14px;color:#2C3E50;
                border-bottom:1px solid #E8E8E8;">
                ${author}
              </td>
            </tr>
            <tr>
              <td style="padding:10px 16px;font-size:12px;color:#7F8C8D;
                font-weight:600;border-bottom:1px solid #E8E8E8;">
                JIRA ISSUE
              </td>
              <td style="padding:10px 16px;font-size:14px;
                border-bottom:1px solid #E8E8E8;">
                ${jiraKeyHtml}
              </td>
            </tr>
            <tr style="background:#F8F9FA;">
              <td style="padding:10px 16px;font-size:12px;color:#7F8C8D;
                font-weight:600;border-bottom:1px solid #E8E8E8;">
                REPO / BRANCH
              </td>
              <td style="padding:10px 16px;font-size:14px;color:#2C3E50;
                border-bottom:1px solid #E8E8E8;">
                <code style="background:#F0F3F4;padding:2px 6px;
                  border-radius:3px;font-size:13px;">${repo}</code>
                &nbsp;/&nbsp;
                <code style="background:#F0F3F4;padding:2px 6px;
                  border-radius:3px;font-size:13px;">${branch}</code>
              </td>
            </tr>
            <tr>
              <td style="padding:10px 16px;font-size:12px;color:#7F8C8D;
                font-weight:600;border-bottom:1px solid #E8E8E8;">
                TARİH
              </td>
              <td style="padding:10px 16px;font-size:14px;color:#2C3E50;
                border-bottom:1px solid #E8E8E8;">
                ${formattedDate}
              </td>
            </tr>
            <tr style="background:#F8F9FA;">
              <td style="padding:10px 16px;font-size:12px;color:#7F8C8D;
                font-weight:600;border-bottom:1px solid #E8E8E8;">
                COMMIT MESAJI
              </td>
              <td style="padding:10px 16px;border-bottom:1px solid #E8E8E8;">
                <code style="background:#F0F3F4;padding:4px 8px;border-radius:3px;
                  font-size:13px;color:#2C3E50;display:inline-block;
                  line-height:1.5;">${commitMessage}</code>
              </td>
            </tr>
            <tr>
              <td style="padding:10px 16px;font-size:12px;color:#7F8C8D;
                font-weight:600;vertical-align:top;">
                DEĞİŞEN DOSYALAR
              </td>
              <td style="padding:10px 16px;">
                <ul style="margin:0;padding-left:18px;">${fileList}</ul>
              </td>
            </tr>
          </table>
        </td>
      </tr>

      <!-- Rapor Sebepleri -->
      <tr>
        <td style="padding:24px 32px 0;">
          <h2 style="margin:0 0 14px;font-size:12px;color:#7F8C8D;
            text-transform:uppercase;letter-spacing:1px;font-weight:600;">
            Raporlanma Nedeni
          </h2>
          <table width="100%" cellpadding="0" cellspacing="0"
            style="border:1px solid #E8E8E8;border-radius:6px;overflow:hidden;">
            ${reasonRows}
          </table>
        </td>
      </tr>

      <!-- Attachment notu -->
      ${attachmentNote}

      <!-- Footer -->
      <tr>
        <td style="background:#F8F9FA;border-top:1px solid #E8E8E8;
          padding:16px 32px;">
          <p style="margin:0;font-size:12px;color:#95A5A6;line-height:1.6;">
            Bu e-posta Cihaz Yazılımları AI Review Pipeline tarafından otomatik
            olarak oluşturulmuştur.<br>
            Sorularınız için sistem yöneticinizle iletişime geçin.
          </p>
        </td>
      </tr>

    </table>
  </td></tr>
</table>

</body>
</html>`;

// ── Mail subject ──────────────────────────────────────────────────────────────
const subject = jiraKey
  ? `[AI-Review] ${jiraKey} için commit raporu`
  : `[AI-Review] ${repo}@${branch} — ${author} commit raporu`;

return [{
  json: {
    jira_key:      jiraKey,
    email_html:    html,
    email_subject: subject,
    hasAttachment: hasDocument,
  },
  binary: inputBinary,
}];

// Jira node'undan gelen veriyi alıyoruz
const issue = $input.first().json;

// 1. "names" kontrolü
if (!issue.names) {
  throw new Error("Lütfen Jira node'unda 'Expand' seçeneğine 'names' eklediğinizden emin olun.");
}

// 2. Reviewer alanının ID'sini dinamik buluyoruz
let reviewerFieldKey = null;
for (const [key, name] of Object.entries(issue.names)) {
  if (name.toLowerCase().includes("reviewer")) {
    reviewerFieldKey = key;
    break;
  }
}

if (!reviewerFieldKey) {
  throw new Error("Jira'da 'Reviewer' isimli bir alan bulunamadı.");
}

// 3. YARDIMCI FONKSİYON: Gelen veri tekil kişi mi yoksa çoklu kişi (Array) mi otomatik çözer
function extractEmails(fieldData) {
  if (!fieldData) return []; // Veri yoksa boş dizi dön

  if (Array.isArray(fieldData)) {
    // Çoklu seçim yapılmışsa map ile e-postaları topla ve boş olanları ele
    return fieldData.map(user => user.emailAddress).filter(email => email);
  } else if (fieldData.emailAddress) {
    // Tek bir kullanıcıysa dizi içinde dön
    return [fieldData.emailAddress];
  }

  return [];
}

// 4. Mailleri yardımcı fonksiyonla temiz bir şekilde çekiyoruz
const reporterEmails = extractEmails(issue.fields.reporter);
const assigneeEmails = extractEmails(issue.fields.assignee);
const reviewerEmails = extractEmails(issue.fields[reviewerFieldKey]);

// 5. Bütün çekilen e-postaları tek bir dizide birleştiriyoruz
const allEmails = [...reporterEmails, ...assigneeEmails, ...reviewerEmails];

// 6. Aynı kişi birden fazla rolde ise (Örn: Assignee aynı zamanda Reviewer ise) tekrarları siliyoruz
const uniqueEmails = [...new Set(allEmails)];

// 7. Attachment binary'sini "Create the Email HTML" node'undan doğrudan çekiyoruz.
//    Ara node'lar (Jira node dahil) binary'i garanti taşımayabildiği için,
//    isim referansıyla kaynaktan tekrar alıyoruz.
const attachmentBinary = $('Create the Email HTML1').first().binary || {};

// Sonucu Email node'u için string'e çevirip döndürüyoruz
return [{
  json: {
    issueKey: issue.key,
    issueSummary: issue.fields.summary,
    reviewerFieldKeyFound: reviewerFieldKey,
    toEmails: uniqueEmails.join(', '), // Virgülle ayrılmış formata çevirir
    hasAttachment: $('Create the Email HTML1').first().json.hasAttachment,
  },
  binary: attachmentBinary,
}];
